            </p>
            <Link href="/#contact">
              <Button 
                variant="default" 
                className="rounded-md"
                data-testid="button-contact-us"
              >
                Get in Touch
              </Button>
            </Link>
          </Card>
        </article>
      </main>

      <Footer />
      <WhatsAppButton />
    </div>
  );
}

